        { OPENROUTER_API_KEY: 'env-fallback-key', DEFAULT_MODEL: 'anthropic/claude-sonnet-4-5' }
      );
      assert.equal(capturedAuthHeader, 'Bearer env-fallback-key');
    } finally {
